import{_ as a,o as t,c as b,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"克林特·巴顿的复合弓","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/6.可升级/克林特·巴顿的复合弓.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/6.可升级/克林特·巴顿的复合弓.md"}'),o={name:"4.资源分区/7.物品与装备/2.武器/远程武器/6.可升级/克林特·巴顿的复合弓.md"};function _(d,e,l,i,p,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"克林特·巴顿的复合弓",tabindex:"-1"},[n("克林特·巴顿的复合弓 "),r("a",{class:"header-anchor",href:"#克林特·巴顿的复合弓","aria-label":'Permalink to "克林特·巴顿的复合弓"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌031")])])],-1),s('<h1 id="克林特·巴顿的复合弓-1" tabindex="-1">克林特·巴顿的复合弓 <a class="header-anchor" href="#克林特·巴顿的复合弓-1" aria-label="Permalink to &quot;克林特·巴顿的复合弓&quot;">​</a></h1><p>克林特·巴顿的复合弓<br> 科技本质<br> 价格∶C+1000<br> 分类∶弓箭<br> 持握∶单手<br> 体积∶3<br> 伤害∶11L<br> 基础：【高速3】【破甲1】【40m射程】【长点射】<br> 描述∶<br> 克林特·巴顿早期使用的复合弓，此时他还不是大名鼎鼎的神盾局特工。马戏团表演者、义警还是无所事事的流浪汉？随你怎么说，但巴顿的箭已经瞄准好了。<br> 弓箭采用暗紫色木质主体与黑色金属配件，弓身刻有磨损痕迹，搭配简易瞄准器和皮质箭袋。弓弦略显陈旧，整体造型朴实无华，却透露出这位“鹰眼”特有的精准与实用风格。<br> 特性：<br> 【世界最佳狙击手】:年纪轻轻的杂技射手克林特·巴顿师从捷射，就是用这把弓箭早早就赢得了赢得了Hawkeye（鹰眼）的称号和“世界最佳狙击手”的赞誉，小心哦，他的百发百中可不仅仅能射穿你头上的苹果。使用这把弓箭进行攻击的时候，你的射击技能检定获得9加骰，额外获得【高速5】</p><p>鹰眼的科技复合弓（差价升级）<br> 科技本质<br> 价格∶B+2000<br> 分类∶弓箭<br> 持握∶单手<br> 体积∶3<br> 伤害∶18L<br> 基础：【高速3】【破甲1】【40m射程】【长点射】<br> 描述∶<br> 克林特·巴顿，还叫他这个名字的人已经很少了，大家都习惯了喊这位神盾局高级特工和复仇者联盟成员的代号—鹰眼。<br> 一切都变好了，不过鹰眼偶尔回想起来在马戏团射苹果的日子，和他那把远不如现在高科技精美但安心的紫色弓箭。<br> 特性：<br> 【神射手】:经历了无数次战斗，鹰眼的箭术已经越发的酣畅淋漓，变成了致命而危险的杀人艺术，你的射击技能鉴定获得8加骰，额外获得【高速5】【破甲5】，并且在此武器在射击时基础射程提升2倍。<br> 每轮一次，射击时消耗1点意志，针对这次攻击而言可以重掷一次，取其中较高的一次进行结算。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',5)])])}const m=a(o,[["render",_]]);export{f as __pageData,m as default};
